// Thẻ "đến hạn" cho nhắc 60/30/5 phút — tự chứa CSS, chỉ phụ thuộc 3 node query + Webhook đến hạn.
const task = $('Lấy công việc (đến hạn)').first().json || {};
const body = $('Webhook đến hạn').first().json.body || {};
let nv = {};
try { nv = $('Lấy nhân viên (đến hạn)').first().json || {}; } catch (e) { nv = {}; }
const tienDo = $input.all().map(i => i.json).filter(r => r && r.task_id);

const moc = String(body.moc || '');
const p = n => String(n).padStart(2, '0');
const fmt = iso => { try { const d = new Date(iso); return `${p(d.getDate())}/${p(d.getMonth()+1)}/${d.getFullYear()} ${p(d.getHours())}:${p(d.getMinutes())}`; } catch (e) { return iso; } };

const band = {
  '60': { text: '⏰ CÒN DƯỚI 1 TIẾNG', color: '#f59e0b', bg: '#fffbeb' },
  '30': { text: '⏰ CÒN DƯỚI 30 PHÚT', color: '#f97316', bg: '#fff7ed' },
  '5':  { text: '🔥 CÒN DƯỚI 5 PHÚT',  color: '#ef4444', bg: '#fef2f2' }
}[moc] || { text: '⏰ SẮP ĐẾN HẠN', color: '#f59e0b', bg: '#fffbeb' };

const assignee = task.name || (body.assignee && body.assignee.name) || 'Chưa giao';
const due = task.due_date ? fmt(task.due_date) : 'N/A';
const last = tienDo.length ? tienDo[tienDo.length - 1] : null;
const progress = last ? `${last.content} — ${fmt(last.time)} · ${last.name || ''}` : 'Chưa có cập nhật';

// ===== ĐÍNH KÈM (của công việc + lần cập nhật tiến độ MỚI NHẤT) =====
// Bản copy đồng bộ với splitZaloAttachments/buildZaloAttachmentText trong src/lib/attachments.js.
// Sửa ở đây là PHẢI sửa cả bên đó (và ngược lại) — xem docs/n8n/nhac-viec-workflows.md.
// MỘT KHỐI duy nhất: ảnh NHÚNG vào lưới trong thẻ (HCTI render) → 10 ảnh vẫn là 1 tin nhắn.
const MAX_EMBED_IMAGES = 10;
const fmtSize = (b) => { const n = Number(b) || 0; return n < 1024 * 1024 ? Math.round(n / 1024) + 'KB' : (Math.round((n / 1024 / 1024) * 10) / 10) + 'MB'; };
const attsTask = Array.isArray(task.attachments) ? task.attachments : [];
const lastTien = tienDo.length ? tienDo[tienDo.length - 1] : null;
const attsTien = (lastTien && Array.isArray(lastTien.attachments)) ? lastTien.attachments : [];
const seenPath = new Set(); const atts = [];
for (const a of [...attsTask, ...attsTien]) {
    const k = a && (a.path || a.url);
    if (k && !seenPath.has(k)) { seenPath.add(k); atts.push(a); }
}
const zImages = [], zLinks = [];
for (const a of atts) {
    if (a.kind === 'image' && zImages.length < MAX_EMBED_IMAGES) zImages.push(a);
    else zLinks.push(a);
}
const attachText = zLinks.length
    ? '\n\n📎 Đính kèm:\n' + zLinks.map(a => '• ' + a.name + ' (' + fmtSize(a.size) + ') — ' + a.url).join('\n')
    : '';
const nImg = atts.filter(a => a.kind === 'image').length;
const nVid = atts.filter(a => a.kind === 'video').length;
const nFile = atts.length - nImg - nVid;
const attachSummary = [nImg ? nImg + ' ảnh' : '', nVid ? nVid + ' video' : '', nFile ? nFile + ' tệp' : ''].filter(Boolean).join(', ');
const attachRow = atts.length ? `<div class="row"><div class="lbl">📎 Đính kèm</div><div class="val">${atts.length} file (${attachSummary})</div></div>` : '';
const attachGrid = zImages.length ? `<div class="att-grid">${zImages.map(a => `<img class="att-img" src="${a.url}"/>`).join('')}</div>` : '';

const html = `<!DOCTYPE html><html lang="vi"><head><meta charset="UTF-8"><style>
  body,html{margin:0;padding:0;width:1920px;min-height:1080px;background:linear-gradient(160deg,#eef2ff,#f8fafc 45%,#ecfeff);font-family:'Segoe UI',Arial,sans-serif;}
  .wrap{padding:60px 80px;}
  .title{font-size:60px;font-weight:800;color:#1e293b;text-align:center;margin:0 0 40px;text-transform:uppercase;}
  .banner{background:${band.bg};border:6px solid ${band.color};color:${band.color};font-size:64px;font-weight:800;text-align:center;padding:32px;border-radius:28px;margin-bottom:44px;}
  .card{background:#fff;border-radius:28px;box-shadow:0 14px 40px rgba(30,41,59,.12);border-left:16px solid ${band.color};overflow:hidden;}
  .row{display:flex;border-bottom:2px solid #eef2f7;}
  .row:last-child{border-bottom:none;}
  .lbl{width:460px;flex-shrink:0;background:#f1f5f9;color:#334155;font-size:38px;font-weight:700;padding:34px 40px;}
  .val{flex:1;font-size:42px;color:#0f172a;padding:34px 44px;line-height:1.35;word-wrap:break-word;}
  .val.strong{font-weight:800;}
  .att-grid{display:flex;flex-wrap:wrap;gap:20px;padding:24px 0 0;}
  .att-img{width:588px;height:442px;object-fit:cover;border-radius:18px;border:3px solid #a78bfa;background:#f5f3ff;}
</style></head><body><div class="wrap">
  <div class="title">Nhắc việc sắp đến hạn</div>
  <div class="banner">${band.text}</div>
  <div class="card">
    <div class="row"><div class="lbl">📋 Công việc</div><div class="val strong">${task.title || ''}</div></div>
    <div class="row"><div class="lbl">⏰ Hạn chót</div><div class="val strong" style="color:${band.color}">${due}</div></div>
    <div class="row"><div class="lbl">📈 Tiến độ gần nhất</div><div class="val">${progress}</div></div>
    <div class="row"><div class="lbl">👤 Người thực hiện</div><div class="val strong">${assignee}</div></div>
    ${attachRow}
  ${attachGrid}
  </div>
</div></body></html>`;

const mention = nv.id_zalo_oa ? `[@${nv.id_zalo_oa}] ` : '';
return [{ json: {
    html,
    message_text: mention + band.text + ' — Tốc độ nhé!' + attachText,
    ms_delay: zImages.length ? 3000 : 1200,   // chờ HCTI tải ảnh đính kèm từ Storage
} }];
